INSERT INTO activities (tenant_id, id, contact_id, deal_id, kind, body, occurred_at) VALUES
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'd958d8ba-0b79-5bab-b1a8-b7dd1b7261be', 'caa20189-5dd7-5a68-bf36-596a0cd9f874', 'd14fbe2e-bc32-5490-ab34-ec9bf5aa00fc', 'call', 'Emergency call from Rosa Camarillo: chiller #2 (NorthCool C-450) at the Westlake Galleria tripped on high head pressure during the afternoon peak. Tenants on floors 4-6 reporting 81F. Dispatched the on-call tech.', '2026-04-26T16:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '87497753-19cf-5040-a2fc-5b4646a90478', 'caa20189-5dd7-5a68-bf36-596a0cd9f874', 'd14fbe2e-bc32-5490-ab34-ec9bf5aa00fc', 'note', 'Field report, Westlake Galleria: C-450 chiller #2 compressor B is down — scored crankshaft, metal in the oil. The temporary repair holds for the season, but both C-450s are 17 years old and on R-22. Recommended a full retrofit over another compressor swap.', '2026-05-01T14:45:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '7280bb4a-68bd-5c2b-951f-4fd35f407a96', 'caa20189-5dd7-5a68-bf36-596a0cd9f874', 'd14fbe2e-bc32-5490-ab34-ec9bf5aa00fc', 'email', 'Sent Rosa the emergency-repair summary plus a preliminary retrofit budget range of $260-300K for replacing both C-450 chillers with magnetic-bearing units.', '2026-05-05T10:20:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '5fc9d87c-60f4-54f9-a06e-9222ddc774e0', 'caa20189-5dd7-5a68-bf36-596a0cd9f874', 'd14fbe2e-bc32-5490-ab34-ec9bf5aa00fc', 'meeting', 'Retrofit walkthrough with Rosa Camarillo and chief engineer Emory Voss: two high-efficiency magnetic-bearing chillers, BAS integration, a Saturday crane day, and a phased cutover so the galleria never loses cooling.', '2026-05-09T13:05:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'e8280802-27ff-51f2-99b5-27a1c2c34172', 'caa20189-5dd7-5a68-bf36-596a0cd9f874', 'd14fbe2e-bc32-5490-ab34-ec9bf5aa00fc', 'email', 'Proposal v2 sent to Rosa: $284,000 total, 14-week equipment lead time, phased cutover plan attached.', '2026-05-14T10:05:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'a1a75557-92a3-58cd-bc0d-1dc6d2a0cca3', 'caa20189-5dd7-5a68-bf36-596a0cd9f874', 'd14fbe2e-bc32-5490-ab34-ec9bf5aa00fc', 'call', 'Rosa: the Pinnacle property board meets on the 24th. They will not sign until we provide a COI naming Pinnacle Property Partners as additional insured.', '2026-05-19T11:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '9c279fd5-49c1-5cc8-aae5-5adde8499794', 'caa20189-5dd7-5a68-bf36-596a0cd9f874', 'd14fbe2e-bc32-5490-ab34-ec9bf5aa00fc', 'note', 'Open items on Westlake: board approval pending, COI request outstanding with our broker, and payment terms — Pinnacle''s standard is net-45, our quote says net-30.', '2026-05-22T16:00:00-05:00'),
