    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '01618a2a-bea8-51ba-942f-76e98401c8fb', '{"action": "issue_quote", "amount": 78720, "deal": "Coppell Distribution Center RTU replacement, phase one", "deal_ref": "demo:deal:7", "discount": 0.18, "terms": "phase one, 10 RTUs, price-match request"}'::jsonb, 'quote-agent', 'Russ asked us to match Apex''s number; drafting the match for a commercial decision.', 96000, 'denied', 'demo-admin', '18% under floor is below cost. Max 10% without VP sign-off — do not match Apex.', '2026-05-04T05:33:16.277437-05:00', '2026-05-05T07:45:47.960266-05:00'),
