    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '92658f0a-073b-51be-9b02-7621fa636ada', '{"action": "send_email", "body_preview": "Hi Sofia \u2014 quote attached for the door-gasket replacements at all three locations, $850 all-in, one visit.", "deal": "Lantana Hospitality walk-in cooler repair + gasket program", "deal_ref": "demo:deal:4", "subject": "Walk-in cooler gasket replacements \u2014 3 locations", "to": "sofia.marchetti@lantanahospitalitygroup.example"}'::jsonb, 'followup-agent', 'Sofia asked for the gasket quote in writing before her Friday ops review; tech found worn gaskets at three locations during the PF-9 repair. $850 is under the L2 auto-execute ceiling — at L2 this email would send itself.', 850, 'pending', NULL, NULL, '2026-06-08T17:24:08.446591-05:00', NULL),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '46d76407-af18-53c1-a97e-0addfc19126b', '{"action": "send_email", "body_preview": "Hi Marisol \u2014 attached is the renewal letter at $44,160/yr (an 8% loyalty discount) with the scope comparison the board asked for.", "deal": "Hill Country ISD service agreement renewal", "deal_ref": "demo:deal:1", "subject": "Hill Country ISD renewal \u2014 8% loyalty discount", "to": "marisol.trevino@hillcountryisd.example"}'::jsonb, 'pipeline-agent', 'Renewal at risk to the Apex bid on price alone; QBR data (99.2% uptime, 3.1-hr response) supports continuity. 8% is inside the discount floor, but $48,000 exceeds the value ceiling — queues at any level below L3.', 48000, 'pending', NULL, NULL, '2026-06-06T14:09:53.654028-05:00', NULL),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '81590f65-f58f-54c0-a37c-a786727be7d4', '{"action": "update_deal", "deal": "Cedar Park Surgical Center OR air-handling install", "deal_ref": "demo:deal:2", "field": "stage", "from": "proposal", "to": "negotiation"}'::jsonb, 'pipeline-agent', 'Beatriz countered on scope (monitoring deferred vs phased payments) and procurement has the vendor packet — the proposal is under active negotiation. Stage should reflect it for pipeline reporting.', 132000, 'pending', NULL, NULL, '2026-06-08T11:00:00.803292-05:00', NULL),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '1061de79-5da8-58d5-89c9-bb5aee4d1050', '{"action": "issue_quote", "amount": 31680, "deal": "Brazos Logistics quarterly PM contract", "deal_ref": "demo:deal:3", "discount": 0.12, "terms": "41 RTUs, 3 sites, quarterly PM, year-one filter program"}'::jsonb, 'quote-agent', 'Dewayne is holding at 12% and procurement signaled they would sign this week at that number. 12% trips the discount guard independently of value — cannot issue without a human call.', 36000, 'pending', NULL, NULL, '2026-06-07T09:32:11.583952-05:00', NULL),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '2dd30b5c-49f0-5e46-915f-c97b7d997e0d', '{"action": "send_email", "body_preview": "Avery \u2014 attached is the renewal letter with a $1,200 service credit, your named account manager, and the written quarterly QBR cadence.", "deal": "Mueller Commons service agreement win-back", "deal_ref": "demo:deal:5", "subject": "Mueller Commons \u2014 our commitment for the next term", "to": "avery.stanhope@muellercommonsreit.example"}'::jsonb, 'followup-agent', 'Win-back letter must arrive before Thursday''s committee. The $1,200 credit sits just over the $1,000 L2 ceiling — close to the line, but the line is real.', 1200, 'pending', NULL, NULL, '2026-06-06T18:51:43.432486-05:00', NULL),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'd54e6857-0021-5f4d-952a-db22bb070279', '{"action": "update_deal", "deal": "Westlake Galleria chiller retrofit", "deal_ref": "demo:deal:0", "field": "stage", "from": "negotiation", "to": "closed_won"}'::jsonb, 'pipeline-agent', 'Rosa''s voicemail says the board vote moved up and Pinnacle may sign by Friday. Premature until the COI lands and terms are countersigned — a human should edit or deny this one.', 284000, 'pending', NULL, NULL, '2026-06-08T11:52:47.623493-05:00', NULL);
INSERT INTO saved_views (tenant_id, id, view_id, version, spec_json, semantic_refs, source_prompt, created_by, created_at) VALUES
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'db45bacd-c11f-5cec-92ed-865eb693f5b0', 'pipeline-health', 1, '{"layout": [{"filter": {"filters": [{"member": "Deals.stage", "operator": "notEquals", "values": ["closed_won", "closed_lost"]}]}, "metric": "Deals.pipeline_value", "title": "Open pipeline ($)", "type": "kpi"}, {"encoding": "vega-lite", "query": {"dimensions": ["Deals.stage"], "measures": ["Deals.count"]}, "title": "Deals by stage", "type": "chart"}, {"query": {"dimensions": ["Deals.title", "Deals.stage"], "filters": [{"member": "Deals.stage", "operator": "notEquals", "values": ["closed_won", "closed_lost"]}], "measures": ["Deals.pipeline_value"]}, "title": "Top open deals", "type": "table"}], "semantic_refs": ["Deals.pipeline_value", "Deals.count", "Deals.stage"], "source_prompt": "Show me overall pipeline health", "title": "Pipeline health", "version": 1, "view_id": "pipeline-health"}'::jsonb, '["Deals.pipeline_value", "Deals.count", "Deals.stage"]'::jsonb, 'Show me overall pipeline health', 'demo-seed', '2026-05-26T14:46:49.757963-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', '466d297a-f89b-5a63-b8cb-646817fb931c', 'renewals-next-90d', 1, '{"layout": [{"filter": {"filters": [{"member": "Deals.title", "operator": "contains", "values": ["renewal"]}]}, "metric": "Deals.count", "title": "Renewal deals in flight", "type": "kpi"}, {"query": {"dimensions": ["Deals.title", "Deals.stage", "Deals.created_at"], "filters": [{"member": "Deals.title", "operator": "contains", "values": ["renewal"]}, {"member": "Deals.stage", "operator": "notEquals", "values": ["closed_won", "closed_lost"]}], "measures": ["Deals.pipeline_value"]}, "title": "Open renewals", "type": "table"}], "semantic_refs": ["Deals.count", "Deals.pipeline_value", "Deals.title"], "source_prompt": "Which service agreements renew in the next 90 days?", "title": "Renewals \u2014 next 90 days", "version": 1, "view_id": "renewals-next-90d"}'::jsonb, '["Deals.count", "Deals.pipeline_value", "Deals.title"]'::jsonb, 'Which service agreements renew in the next 90 days?', 'demo-seed', '2026-06-01T08:07:38.819703-05:00');
INSERT INTO documents (tenant_id, source, ref_id, content, created_at) VALUES
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:0', 'Call — Westlake Galleria chiller retrofit (2026-04-26): Emergency call from Rosa Camarillo: chiller #2 (NorthCool C-450) at the Westlake Galleria tripped on high head pressure during the afternoon peak. Tenants on floors 4-6 reporting 81F. Dispatched the on-call tech.', '2026-04-26T16:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:1', 'Note — Westlake Galleria chiller retrofit (2026-05-01): Field report, Westlake Galleria: C-450 chiller #2 compressor B is down — scored crankshaft, metal in the oil. The temporary repair holds for the season, but both C-450s are 17 years old and on R-22. Recommended a full retrofit over another compressor swap.', '2026-05-01T14:45:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:2', 'Email — Westlake Galleria chiller retrofit (2026-05-05): Sent Rosa the emergency-repair summary plus a preliminary retrofit budget range of $260-300K for replacing both C-450 chillers with magnetic-bearing units.', '2026-05-05T10:20:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:3', 'Meeting — Westlake Galleria chiller retrofit (2026-05-09): Retrofit walkthrough with Rosa Camarillo and chief engineer Emory Voss: two high-efficiency magnetic-bearing chillers, BAS integration, a Saturday crane day, and a phased cutover so the galleria never loses cooling.', '2026-05-09T13:05:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:4', 'Email — Westlake Galleria chiller retrofit (2026-05-14): Proposal v2 sent to Rosa: $284,000 total, 14-week equipment lead time, phased cutover plan attached.', '2026-05-14T10:05:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:5', 'Call — Westlake Galleria chiller retrofit (2026-05-19): Rosa: the Pinnacle property board meets on the 24th. They will not sign until we provide a COI naming Pinnacle Property Partners as additional insured.', '2026-05-19T11:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:6', 'Note — Westlake Galleria chiller retrofit (2026-05-22): Open items on Westlake: board approval pending, COI request outstanding with our broker, and payment terms — Pinnacle''s standard is net-45, our quote says net-30.', '2026-05-22T16:00:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:7', 'Meeting — Westlake Galleria chiller retrofit (2026-05-28): Terms session with Rosa and their controller: they pushed net-45; we floated net-30 with a 2% early-pay credit. Rosa is taking the credit option to the board with the retrofit vote.', '2026-05-28T14:50:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:8', 'Email — Westlake Galleria chiller retrofit (2026-05-31): Re-sent the COI request to the broker and copied Rosa so Pinnacle can see it is in motion before the board date.', '2026-05-31T11:20:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:9', 'Call — Westlake Galleria chiller retrofit (2026-06-07): Voicemail from Rosa: the board vote moved up a week. She asked whether we can hold the 14-week lead time if Pinnacle signs by Friday. Flagged to scheduling.', '2026-06-07T08:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:10', 'Call — Hill Country ISD service agreement renewal (2026-03-27): Marisol Trevino called: the Hill Country ISD board is taking the district maintenance contract to competitive bid this cycle. Apex Air Systems has submitted.', '2026-03-27T09:45:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:11', 'Note — Hill Country ISD service agreement renewal (2026-04-04): Account context: 6 years incumbent on Hill Country ISD — 11 campuses, 96 rooftop units (mostly Kestrel KX-90s). Current agreement: $48,000/yr, expires end of July.', '2026-04-04T17:30:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:12', 'Email — Hill Country ISD service agreement renewal (2026-04-12): Sent Marisol the renewal proposal at $48,000/yr, same scope: quarterly PM on all campuses, 4-hour emergency response during school hours.', '2026-04-12T08:20:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:13', 'Meeting — Hill Country ISD service agreement renewal (2026-04-22): Renewal QBR with Marisol and Glenn Okafor (CFO): uptime 99.2% across the KX-90 fleet, average emergency response 3.1 hours, zero school days lost to HVAC since 2024.', '2026-04-22T09:50:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:14', 'Note — Hill Country ISD service agreement renewal (2026-05-02): Renewal is at risk on price alone. Proposed an 8% loyalty discount ($44,160/yr) to defuse the Apex bid — needs Greenlight before it goes to the district.', '2026-05-02T10:40:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:15', 'Call — Hill Country ISD service agreement renewal (2026-05-08): Glenn Okafor wants an apples-to-apples scope comparison against the Apex bid before the board packet closes.', '2026-05-08T17:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:16', 'Email — Hill Country ISD service agreement renewal (2026-05-18): Sent Glenn the scope-comparison matrix: Apex''s bid excludes filter media and after-hours response — line-itemed the gap.', '2026-05-18T10:10:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:17', 'Note — Hill Country ISD service agreement renewal (2026-05-25): Marisol, off the record: the facilities committee prefers continuity; the board just needs cover on price. The 8% letter likely closes it.', '2026-05-25T12:45:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:18', 'Call — Hill Country ISD service agreement renewal (2026-06-02): Decision expected at the June board meeting. Marisol asked us to hold the discount offer open through the vote.', '2026-06-02T12:10:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:19', 'Meeting — Cedar Park Surgical Center OR air-handling install (2026-04-22): Site scoping at Cedar Park Surgical Center with Beatriz Lindqvist: OR air-handling install — two AHUs, HEPA terminal filtration, room-pressure monitoring across 4 ORs and sterile storage.', '2026-04-22T10:05:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:20', 'Email — Cedar Park Surgical Center OR air-handling install (2026-05-01): Proposal sent: $132,000 — equipment, install, balancing, and commissioning, sequenced around the surgery schedule (nights and weekends).', '2026-05-01T16:10:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:21', 'Call — Cedar Park Surgical Center OR air-handling install (2026-05-07): Beatriz countered on scope: she wants the room-pressure monitoring package pulled to a later phase to get under this year''s capital budget.', '2026-05-07T15:20:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:22', 'Note — Cedar Park Surgical Center OR air-handling install (2026-05-10): Compliance subplot: Cedar Park''s state health-facility licensure audit is this fall — they need IQ/OQ commissioning documentation from us as part of the package. Flagged to our controls sub.', '2026-05-10T09:50:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:23', 'Email — Cedar Park Surgical Center OR air-handling install (2026-05-19): Sent option B: $118,000 with monitoring deferred, plus the compliance-documentation plan (IQ/OQ protocols, balancing reports, filter certs).', '2026-05-19T11:05:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:24', 'Note — Cedar Park Surgical Center OR air-handling install (2026-05-22): Procurement step: Hal Crowder requires the vendor packet — W-9, insurance certs, references. Submitted today.', '2026-05-22T14:20:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:25', 'Call — Cedar Park Surgical Center OR air-handling install (2026-05-30): Beatriz is leaning back to the full $132K option A if we can phase the payments across two fiscal years. Checking with our controller.', '2026-05-30T08:30:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:26', 'Meeting — Cedar Park Surgical Center OR air-handling install (2026-06-04): Walked the mechanical mezzanine with their engineer of record; confirmed structural capacity for the new AHUs. Decision targeted before their July capital meeting.', '2026-06-04T14:05:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:27', 'Meeting — Brazos Logistics quarterly PM contract (2026-05-08): Walked all three Brazos Logistics cross-dock facilities with Dewayne Kessler: 41 rooftop units across the sites, a third of them past 12 years old, no consistent PM history.', '2026-05-08T12:50:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:28', 'Email — Brazos Logistics quarterly PM contract (2026-05-14): Sent the quarterly PM proposal: $36,000/yr covering all 41 RTUs, filters and belts included, priority dispatch for dock-door heaters in winter.', '2026-05-14T17:10:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:29', 'Call — Brazos Logistics quarterly PM contract (2026-05-19): Dewayne is demanding a 12% discount and says Apex Air Systems quoted a cheaper per-unit rate. He runs ops lean and negotiates everything.', '2026-05-19T11:45:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:30', 'Note — Brazos Logistics quarterly PM contract (2026-05-23): Our discount floor is 10% without VP sign-off. A 12% quote has to clear Greenlight — do not issue without approval.', '2026-05-23T11:00:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:31', 'Email — Brazos Logistics quarterly PM contract (2026-05-28): Countered with 7% as a multi-site discount plus a no-charge filter program for year one; held the line on response times.', '2026-05-28T08:30:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:32', 'Call — Brazos Logistics quarterly PM contract (2026-05-31): Dewayne holding at 12%. Tamika Brandt (procurement) hinted they would sign this week at that number.', '2026-05-31T13:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:33', 'Note — Brazos Logistics quarterly PM contract (2026-06-05): Quote at 12% drafted for the approval queue with the Apex context attached; commercial call needed.', '2026-06-05T13:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:34', 'Call — Lantana Hospitality walk-in cooler repair + gasket program (2026-05-08): Sofia Marchetti reported the walk-in cooler icing up at the Lantana Domain-area restaurant; line cooks are shutting the unit down overnight.', '2026-05-08T10:45:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:35', 'Note — Lantana Hospitality walk-in cooler repair + gasket program (2026-05-14): Tech visit: replaced a failed evaporator-fan motor on the Permafrost PF-9 walk-in. Found worn door gaskets at this location and two others on the same route.', '2026-05-14T11:00:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:36', 'Email — Lantana Hospitality walk-in cooler repair + gasket program (2026-05-21): Sent Sofia the repair summary; flagged the gasket wear at three locations and recommended replacing all of them in one visit.', '2026-05-21T15:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:37', 'Note — Lantana Hospitality walk-in cooler repair + gasket program (2026-05-27): Upsell drafted: gasket replacements across the three locations at $850 all-in. Follow-up email queued for approval.', '2026-05-27T08:40:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:38', 'Call — Lantana Hospitality walk-in cooler repair + gasket program (2026-06-03): Sofia asked for the gasket quote in writing before her Friday ops review — she expects a quick yes.', '2026-06-03T09:45:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:39', 'Note — Mueller Commons service agreement win-back (2026-03-05): Account review, Mueller Commons REIT: we missed the last 3 QBRs after our account manager left. The relationship is cold; renewal is in 60 days.', '2026-03-05T08:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:40', 'Call — Mueller Commons service agreement win-back (2026-03-18): Avery Stanhope was blunt: Apex Air Systems quoted 15% under our current rate, and Mueller''s asset manager wants a reason not to switch.', '2026-03-18T08:50:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:41', 'Meeting — Mueller Commons service agreement win-back (2026-04-01): Win-back meeting on-site with Avery and chief engineer Bo Lindgren. Bo backs our techs — 41 closed tickets, no repeat failures on the ClimaCore CC-30 towers.', '2026-04-01T15:30:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:42', 'Note — Mueller Commons service agreement win-back (2026-04-08): Post-mortem: the misses were ours. Win-back plan: a $1,200 service credit, a named account manager, and a written quarterly QBR cadence.', '2026-04-08T16:50:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:43', 'Email — Mueller Commons service agreement win-back (2026-04-19): Sent Avery the renewal-at-current-rate summary while the credit offer clears internal approval.', '2026-04-19T11:00:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:44', 'Call — Mueller Commons service agreement win-back (2026-04-29): Avery: the asset manager will take continuity to committee if the credit and the QBR commitment arrive in writing this week.', '2026-04-29T15:45:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:45', 'Note — Mueller Commons service agreement win-back (2026-05-12): Win-back email with the $1,200 service credit drafted; queued for Greenlight.', '2026-05-12T14:50:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:46', 'Meeting — Mueller Commons service agreement win-back (2026-05-22): Bo walked us through the cooling-tower fill replacement he wants next quarter — scoped into the renewal as an option, not a condition.', '2026-05-22T14:30:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:47', 'Call — Mueller Commons service agreement win-back (2026-05-30): Committee meets Thursday. Avery asked for the final letter no later than Wednesday noon.', '2026-05-30T16:30:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:48', 'Call — Travis Heights Medical Plaza renewal FY27 (2026-03-01): Renewal cycle opened with Noor Haddad at Travis Heights Medical Plaza: current agreement $52,000/yr, expires June 30.', '2026-03-01T17:30:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:49', 'Meeting — Travis Heights Medical Plaza renewal FY27 (2026-03-10): Annual review with Noor and Felix Arambula: 99.6% uptime across the plaza, both TruFlow TF-8 boilers passed inspection, negative-pressure suites held spec all year.', '2026-03-10T14:20:00-05:00');
INSERT INTO documents (tenant_id, source, ref_id, content, created_at) VALUES
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'email', 'demo:doc:act:50', 'Email — Travis Heights Medical Plaza renewal FY27 (2026-03-17): Sent the renewal at $52,000/yr — same scope, added semi-annual coil cleaning at no charge as a loyalty inclusion.', '2026-03-17T08:15:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'upload', 'demo:doc:act:51', 'Note — Travis Heights Medical Plaza renewal FY27 (2026-03-20): Noor flagged one concern: response time on the March after-hours call was 5 hours. Walked her through the on-call rotation fix we made in April.', '2026-03-20T12:20:00-05:00'),
    ('a268eeba-fe8d-5372-8dcc-76de87baa789', 'call', 'demo:doc:act:52', 'Call — Travis Heights Medical Plaza renewal FY27 (2026-03-27): Noor confirmed the medical plaza''s ownership group approved the renewal without taking it to bid.', '2026-03-27T17:30:00-05:00'),
